<template><div class="grid"><section class="galaxy-card span5"><h3 class="section-title">直播脚本编辑</h3><el-form label-position="top" class="form-grid"><el-form-item label="标题"><el-input v-model="form.title" /></el-form-item><el-form-item label="分类"><el-select v-model="form.category" style="width:100%"><el-option label="开场" value="开场"/><el-option label="互动" value="互动"/><el-option label="促单" value="促单"/><el-option label="收尾" value="收尾"/></el-select></el-form-item><el-form-item label="内容"><el-input v-model="form.content" type="textarea" :rows="10" maxlength="3000" show-word-limit /></el-form-item><div><el-button type="primary" @click="save">{{form.id?'更新脚本':'保存脚本'}}</el-button><el-button @click="reset">新建</el-button><el-button :type="timer?'danger':'success'" @click="toggleTimer">{{timer?'停止排练':'开始排练'}} {{elapsed}}s</el-button></div></el-form></section><section class="galaxy-card span7"><div class="page-title"><h3 class="section-title">脚本列表</h3><el-button @click="load">刷新</el-button></div><div v-for="s in scripts" :key="s.id" class="script-card"><div class="page-title"><b>{{s.title}}</b><el-tag>{{s.category}}</el-tag></div><p>{{s.content}}</p><el-button link @click="edit(s)">编辑</el-button><el-button link @click="$router.push('/tts')">去合成</el-button><el-popconfirm title="确认删除？" @confirm="remove(s.id)"><template #reference><el-button link type="danger">删除</el-button></template></el-popconfirm></div></section></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getScriptList,createScript,updateScript,deleteScript } from '@/api/scripts';const scripts=ref([]),elapsed=ref(0),timer=ref(null);const form=reactive({id:null,title:'',category:'开场',content:''});async function load(){scripts.value=await getScriptList()}onMounted(load);function reset(){Object.assign(form,{id:null,title:'',category:'开场',content:''})}function edit(row){Object.assign(form,row)}async function save(){if(!form.title||!form.content)return ElMessage.warning('请填写标题和内容');form.id?await updateScript(form.id,form):await createScript(form);ElMessage.success('已保存');reset();load()}async function remove(id){await deleteScript(id);ElMessage.success('已删除');load()}function toggleTimer(){if(timer.value){clearInterval(timer.value);timer.value=null}else{elapsed.value=0;timer.value=setInterval(()=>elapsed.value++,1000)}}</script>
